using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using System.Text.RegularExpressions;
using System.Web;

namespace ResearchAgent;

/// <summary>
/// Provides web search and page-fetching tools for the research agent.
/// Uses the DuckDuckGo instant-answer API (no API key required).
/// </summary>
public sealed partial class WebSearch
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (compatible)" },
            { "Accept",     "text/html,application/json" },
        },
    };

    // ── Web search ──────────────────────────────────────────────────────

    [Description("Search the web for information. Returns relevant snippets and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔎 Searching: {query}");

        try
        {
            var encoded = HttpUtility.UrlEncode(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var ddg = await s_http.GetFromJsonAsync(url, DdgJsonContext.Default.DdgResponse);
            if (ddg is null)
                return "No results found.";

            var results = new List<string>();

            if (!string.IsNullOrWhiteSpace(ddg.AbstractText))
                results.Add($"[{ddg.AbstractSource}] {ddg.AbstractText}\n  URL: {ddg.AbstractUrl}");

            if (ddg.RelatedTopics is not null)
            {
                foreach (var topic in ddg.RelatedTopics)
                {
                    if (!string.IsNullOrWhiteSpace(topic.Text))
                    {
                        results.Add($"- {topic.Text}\n  URL: {topic.FirstUrl}");
                    }

                    // Handle grouped sub-topics
                    if (topic.Topics is not null)
                    {
                        foreach (var sub in topic.Topics.Take(3))
                        {
                            if (!string.IsNullOrWhiteSpace(sub.Text))
                                results.Add($"- {sub.Text}\n  URL: {sub.FirstUrl}");
                        }
                    }
                }
            }

            if (results.Count == 0)
                return "No results found. Try rephrasing the query.";

            // Cap to avoid flooding context
            return string.Join("\n\n", results.Take(8));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    // ── Fetch page ──────────────────────────────────────────────────────

    [Description("Fetch a web page and return its text content (truncated to ~4000 chars).")]
    public async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        Console.WriteLine($"  🌐 Fetching: {url}");

        try
        {
            var html = await s_http.GetStringAsync(url);
            var text = StripHtml(html);

            // Truncate to keep context window manageable
            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[...truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Page returned no readable text."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    // ── HTML helpers ────────────────────────────────────────────────────

    private static string StripHtml(string html)
    {
        // Remove script/style blocks entirely
        html = ScriptStyleRegex().Replace(html, " ");
        // Remove all HTML tags
        html = TagRegex().Replace(html, " ");
        // Decode common entities
        html = html
            .Replace("&amp;",  "&")
            .Replace("&lt;",   "<")
            .Replace("&gt;",   ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;",  "'")
            .Replace("&nbsp;", " ");
        // Collapse whitespace
        html = WhitespaceRegex().Replace(html, " ").Trim();
        return html;
    }

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.IgnoreCase | RegexOptions.Singleline)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex WhitespaceRegex();
}

// ── DuckDuckGo response DTOs ────────────────────────────────────────────

public sealed class DdgResponse
{
    [JsonPropertyName("AbstractText")]
    public string? AbstractText { get; set; }

    [JsonPropertyName("AbstractSource")]
    public string? AbstractSource { get; set; }

    [JsonPropertyName("AbstractURL")]
    public string? AbstractUrl { get; set; }

    [JsonPropertyName("RelatedTopics")]
    public List<DdgTopic>? RelatedTopics { get; set; }
}

public sealed class DdgTopic
{
    [JsonPropertyName("Text")]
    public string? Text { get; set; }

    [JsonPropertyName("FirstURL")]
    public string? FirstUrl { get; set; }

    // Grouped sub-topics (DuckDuckGo nests some topics under a category)
    [JsonPropertyName("Topics")]
    public List<DdgTopic>? Topics { get; set; }
}

[JsonSerializable(typeof(DdgResponse))]
internal sealed partial class DdgJsonContext : JsonSerializerContext;

using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// Simple in-memory note store used by the research agent to collect
/// findings before producing a final summary.
/// </summary>
public sealed class ResearchNotes
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key findings as you discover them.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📌 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        Console.WriteLine($"  📋 Returning {_notes.Count} note(s)");

        var numbered = _notes.Select((n, i) => $"[{i + 1}] {n}");
        return string.Join("\n\n", numbered);
    }
}

